import{_ as e,o as i,c as l,a2 as t}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F15: 關係人交易與利益輸送風險 - finance-financial-analyst 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3189_景碩/20260423/F15_關係人交易與利益輸送風險_財務分析專家.md","filePath":"審計報告庫/財務審計/3189_景碩/20260423/F15_關係人交易與利益輸送風險_財務分析專家.md"}'),n={name:"審計報告庫/財務審計/3189_景碩/20260423/F15_關係人交易與利益輸送風險_財務分析專家.md"};function o(r,a,s,c,d,_){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="f15-關係人交易與利益輸送風險-finance-financial-analyst-審計報告" tabindex="-1">F15: 關係人交易與利益輸送風險 - finance-financial-analyst 審計報告 <a class="header-anchor" href="#f15-關係人交易與利益輸送風險-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F15: 關係人交易與利益輸送風險 - finance-financial-analyst 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>是否存在異常大額的關係人交易(連屬公司、子公司)？其定價是否符合市場行情？是否存在利益輸送或虛增利潤之嫌？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>截至2025年全年最新公開數據，景碩關係人交易規模極低，應收關係人帳款僅0.9M，佔總資產0.001%。主要關係人為子公司晶碩光學(持股57%)，其營運獨立且為上市公司(6491)。2024年底取消處分蘇州統碩案屬正常決策，內部人持股由25.25%升至28.47%。治理風險等級判定A(良)，目前無異常利益輸送。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A(良) — 關係人應收帳款餘額0.9M(2025Q4)、其他應收款0元，對比總資產79.97B、營收39.35B，佔比趨近於零。關係人交易主要為子公司晶碩光學的常規銷貨，晶碩本身為上市公司(6491)，財務資訊公開透明，具備外部市場定價錨。母公司對晶碩持股約57%，2025年法說會指出晶碩貢獻合併營收約18%，屬正常垂直整合範疇。無重大資金貸與、背書保證異常情形。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>1. 交易規模實測：</strong></p><ul><li>應收關係人帳款淨額逐季變動: 2023Q2: 1.5M → 2024Q2: 0.02M → 2025Q2: 0.01M → 2025Q4: 0.87M</li><li>其他應收關係人款項: 2024Q3: 7.0M → 2024Q4: 7.1M → 2025Q1: 1.1M → 2025Q2: 2.1M → 2025Q3: 4.8M → 2025Q4: 0</li><li>以上金額相對於總資產(~80B)及營收(~39B)可完全忽略，未有超過20%交易比例之高治理風險情形</li><li>關係人進銷貨方面，從法說會揭露晶碩貢獻合併營收18%，但這屬合併報表內子公司正常業務，非異常關聯交易</li></ul><p><strong>2. 帳期異常偵測：</strong></p><ul><li>關係人應收款週轉天數: 按0.9M餘額/年化關係人交易(假設約7B晶碩營收)推估&lt;1天，顯著低於一般客戶週轉天數(~50天)</li><li>帳期極短反映集團內交易多以現金或即期結算，無資金占用風險</li><li>關係人應付款未在FinMind資產負債表中獨立揭露，側面證明金額極低</li></ul><p><strong>3. 子公司利潤滲透與治理穿透：</strong></p><ul><li>晶碩光學(6491)為獨立掛牌公司，FY2025營運穩定成長，無承接母公司不良資產或虛增利潤跡象</li><li>景碩持有晶碩57%，合併報表中已完全沖銷內部交易，無利潤藏匿空間</li><li>2024年12月景碩與和碩同步公告取消處分大陸子公司(蘇州統碩/世碩)，最初公告於2023年底。處分案取消原因是監管審批不確定性，決策合理，非異常利益輸送</li></ul><p><strong>4. 內部人持股異動(必檢項)：</strong></p><ul><li>董監持股比例: 2025年12月25.25% → 2026年3月28.47%，上升3.22ppts，趨勢正面</li><li>大股東持股(千張): 62.19%(2026/04/17)，籌碼集中且持續上升</li><li>2024年9月經理人吳蔚文申報信託19張，金額僅2M，屬例行財務規劃，無異常拋售</li><li>yinfo顯示Insider持股33%，Institution持股12.8%，內部人持股偏高且穩定，誠信風險低</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>從華爾街空頭視角審讀景碩的關係人交易，結論是目前無明顯利益輸送跡象，但有兩個結構性治理觀察點：</p><p><strong>風險層面：</strong> 景碩-晶碩的母子關係是典型的「控股母公司+金雞母子公司」結構。晶碩貢獻18%合併營收但隱形眼鏡業務與ABF載板本業完全無關，本質上是財務投資而非營運整合。當景碩本業低迷時，晶碩穩定的股利分配成為損益表的隱形撐腰——這本身並非問題，但投資者需警惕：若晶碩將來分拆或減資，母公司可能面臨一次性業外收益驟減，市場卻可能將其解讀為「本業獲利能力不足」。此外，和碩集團(4938)為景碩大股東背景，集團內部資源配置(如處分大陸廠區同步決策)顯示經營權高度集中。目前無異常，但投資人需追蹤大股東股權移轉情況，若出現連續申報轉讓&gt;1%持股，視為治理警訊。</p><p><strong>待穿透風險：</strong> 境外子公司架構尚待年報逐一穿透，尤其蘇州統碩的資產處置動向仍需關注。若景碩持續擴大海外子公司投資，建議每半年檢視關係人交易餘額變化。</p><p><strong>物理對策：</strong></p><ul><li>設置關係人交易閾值監控: 若任一單項半年內關係人應收款&gt;500M(佔營收&gt;1.3%)需觸發深度審計</li><li>關注2025年年報之關係人附註對晶碩交易的逐筆披露</li><li>監控和碩集團(大股東層)的股權變動，若出現連續申報轉讓&gt;1%持股，視為治理警訊</li></ul><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>FinMind 數據採集器</code>: <code>balance_sheet 3189 2023-04-01 2026-04-23 --df</code> (科目: AccountsReceivableDuefromRelatedPartiesNet, OtherReceivablesDueFromRelatedParties)</li><li>Web: <code>富果法說會備忘錄 2025-08-19</code> (揭露: 晶碩貢獻合併營收約18%)</li><li>Web: <code>CMoney股市爆料同學會</code> (揭露: 董監持股比例由25.25%升至28.47%)</li><li>Web: <code>鉅亨網 2024-09-23</code> (揭露: 經理人吳蔚文信託19張)</li><li>Web: <code>自由財經 2024-12</code> (揭露: 和碩、景碩同步取消處分中國大陸子公司)</li><li><code>yfinance</code>: <code>yf_info 3189.TW</code> (科目: heldPercentInsiders 0.33008, heldPercentInstitutions 0.12827)</li></ul>',24)])])}const p=e(n,[["render",o]]);export{u as __pageData,p as default};
